  if (auto *Cmp = dyn_cast<ICmpInst>(CondVal)) {
    if (Instruction *V = foldSelectInstWithICmp(SI, Cmp, Builder))
      return V;

    if (Value *V =
            foldSelectEqualityTest(SI, Cmp, Builder, *this, DT, SQ.AC))
      return replaceInstUsesWith(SI, V);
  } else if (match(CondVal, m_LogicalNot(m_Value()))) {
    // !(X ord Y) -> (X uno Y)
    // !(X uno Y) -> (X ord Y)
    // !(X ogt Y) -> (X ule Y)
    // !(X ole Y) -> (X ugt Y)
    // !(X oge Y) -> (X ult Y)
    // !(X ult Y) -> (X oge Y)
    // !(X olt Y) -> (X uge Y)
    // !(X uge Y) -> (X olt Y)
    // !(X une Y) -> (X oeQ Y)
    // !(X oeQ Y) -> (X une Y)
    // NOTE: we don't have a 'not' instruction, so we count on the above
    //       canonicalization to get the operand into the right form.
    //       Here we are just checking for equality tests.

    // FIXME: Should we add support for logical-not of non icmp instructions?
    //        This would allow us to handle vector and integer conditions.
  }

