    return replaceInstUsesWith(SI, V);

  if (Value *V = foldSelectOpOp(SI, dyn_cast<Instruction>(TrueVal),
                                dyn_cast<Instruction>(FalseVal)))
    return replaceInstUsesWith(SI, V);

  if (Instruction *V = foldSelectValueEquivalence(SI, DT))
    return V;

  if (Instruction *V = foldAndOrOfSelectUsingImpliedCond(TrueVal, FalseVal, SI))
    return V;
  if (Instruction *V = foldAndOrOfSelectUsingImpliedCond(FalseVal, TrueVal, SI))
    return V;

  if (Instruction *V = foldSelectExtConst(SI))
    return V;

  if (Instruction *V = foldVectorSelect(SI))
    return V;

  // See if we can fold the select into one of our operands.
  if (auto *TI = dyn_cast<Instruction>(TrueVal))
    if (Instruction *V = foldSelectIntoPhi(SI, TI, FalseVal))
      return V;
  if (auto *FI = dyn_cast<Instruction>(FalseVal))
    if (Instruction *V = foldSelectIntoPhi(SI, FI, TrueVal))
      return V;

  // Try to eliminate select instructions that test the leading bit of an
  // integer by using arithmetic/logical shifts instead.
  if (auto *BO = dyn_cast<BinaryOperator>(CondVal)) {
    // select (ashr X, sizeof(X)*8-1), -1, X --> X
    // select (lshr X, sizeof(X)*8-1), X, 0 --> X
    // select (ashr X, sizeof(X)*8-1), Y, X --> select (ashr X, sizeof(X)*8-1), Y, 0
    // select (lshr X, sizeof(X)*8-1), X, Y --> select (lshr X, sizeof(X)*8-1), 0, Y
    Value *X;
    const APInt *C;
    if (match(BO, m_AShr(m_Value(X), m_Power2(C))) &&
        *C == X->getType()->getScalarSizeInBits() - 1) {
      if (TrueVal == Constant::getAllOnesValue(TrueVal->getType()) &&
          FalseVal == X)
        return replaceInstUsesWith(SI, X);
      if (FalseVal == X)
        return replaceOperand(SI, 2, ConstantInt::get(FalseVal->getType(), 0));
    } else if (match(BO, m_LShr(m_Value(X), m_Power2(C))) &&
               *C == X->getType()->getScalarSizeInBits() - 1) {
      if (TrueVal == X && FalseVal == ConstantInt::get(FalseVal->getType(), 0))
        return replaceInstUsesWith(SI, X);
      if (TrueVal == X)
        return replaceOperand(SI, 1, ConstantInt::get(TrueVal->getType(), 0));
    }
  }

  // select (trunc nuw X to i1), X, Y --> select (trunc nuw X to i1), -1, Y
  // select (trunc nuw X to i1), Y, X --> select (trunc nuw X to i1), Y, 0
  // select (trunc nsw X to i1), X, Y --> select (trunc nsw X to i1), -1, Y
  // select (trunc nsw X to i1), Y, X --> select (trunc nsw X to i1), Y, 0
  Value *Trunc;
  if (match(CondVal, m_NUWTrunc(m_Value(Trunc)))) {
    if (TrueVal == Trunc)
      return replaceOperand(SI, 1, ConstantInt::get(TrueVal->getType(), 1));
    if (FalseVal == Trunc)
      return replaceOperand(SI, 2, ConstantInt::get(FalseVal->getType(), 0));
  }
  if (match(CondVal, m_NSWTrunc(m_Value(Trunc)))) {
    if (TrueVal == Trunc)
      return replaceOperand(SI, 1,
                            Constant::getAllOnesValue(TrueVal->getType()));
    if (FalseVal == Trunc)
      return replaceOperand(SI, 2, ConstantInt::get(FalseVal->getType(), 0));
  }

  return nullptr;
}
